# Deobfuscated structure

HereÔÇÖs the same code rewritten into a readable version with sane names.

```javascript
const TAU = 6.283;
const PHI = 1.618;
const ROOT_HALF = 0.707;

const config = {
  attraction: 4000,
  springCoeff: 0.004,
  amplification: 0.92,
  streamDrift: 0.0003,
  streamLimit: 40,
  streamDecay: 0.04,
  theta: 0.06
};

const nodes = [
  { id: 'hub',     label: 'Hub',     r: 26, x: 400, y: 300, vx: 0, vy: 0 },
  { id: 'alpha',   label: 'Alpha',   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
  { id: 'beta',    label: 'Beta',    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
  { id: 'gamma',   label: 'Gamma',   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
  { id: 'delta',   label: 'Delta',   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
  { id: 'epsilon', label: 'Epsilon', r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

const springs = [
  { a: 'hub',   b: 'alpha',   rest: 160, k: 0.006 },
  { a: 'hub',   b: 'beta',    rest: 160, k: 0.005 },
  { a: 'hub',   b: 'gamma',   rest: 170, k: 0.004 },
  { a: 'hub',   b: 'delta',   rest: 170, k: 0.004 },
  { a: 'hub',   b: 'epsilon', rest: 180, k: 0.003 },
  { a: 'alpha', b: 'beta',    rest: 200, k: 0.002 },
  { a: 'gamma', b: 'delta',   rest: 220, k: 0.002 },
  { a: 'alpha', b: 'epsilon', rest: 200, k: 0.002 }
];

const camera = { x: 400, y: 300, zoom: 1 };
const cameraTarget = { x: 400, y: 300, zoom: 1 };

const particles = [];
let tick = 0;

function getNode(id) {
  for (let i = 0; i < nodes.length; i++) {
    if (nodes[i].id === id) return nodes[i];
  }
  return null;
}

function updateNodes() {
  // pairwise attraction
  for (let i = 0; i < nodes.length; i++) {
    for (let j = i + 1; j < nodes.length; j++) {
      const dx = nodes[i].x - nodes[j].x;
      const dy = nodes[i].y - nodes[j].y;
      const dist = Math.sqrt(dx * dx + dy * dy) || 1;

      const force = config.attraction / (dist * dist);
      const fx = (dx / dist) * force;
      const fy = (dy / dist) * force;

      nodes[i].vx += fx;
      nodes[i].vy += fy;
      nodes[j].vx -= fx;
      nodes[j].vy -= fy;
    }
  }

  // springs
  for (let i = 0; i < springs.length; i++) {
    const n1 = getNode(springs[i].a);
    const n2 = getNode(springs[i].b);
    if (!n1 || !n2) continue;

    const dx = n2.x - n1.x;
    const dy = n2.y - n1.y;
    const dist = Math.sqrt(dx * dx + dy * dy) || 1;

    const stretch = dist - springs[i].rest;
    const force = (springs[i].k || config.springCoeff) * stretch;

    n1.vx += (dx / dist) * force;
    n1.vy += (dy / dist) * force;
    n2.vx -= (dx / dist) * force;
    n2.vy -= (dy / dist) * force;
  }

  // damping + drift toward center
  for (let i = 0; i < nodes.length; i++) {
    nodes[i].vx += (400 - nodes[i].x) * config.streamDrift;
    nodes[i].vy += (300 - nodes[i].y) * config.streamDrift;

    nodes[i].vx *= config.amplification;
    nodes[i].vy *= config.amplification;

    nodes[i].x += nodes[i].vx;
    nodes[i].y += nodes[i].vy;
  }
}

function spawnParticle() {
  if (particles.length >= config.streamLimit) return;

  const source = nodes[Math.floor(Math.random() * nodes.length)];
  const angle = Math.random() * TAU;
  const speed = 0.3 + Math.random() * ROOT_HALF;

  particles.push({
    x: source.x,
    y: source.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + (Math.random() * PHI) * ROOT_HALF
  });
}

function updateParticles() {
  for (let i = particles.length - 1; i >= 0; i--) {
    const p = particles[i];

    p.x += p.vx;
    p.y += p.vy;
    p.vx *= 1 - config.streamDecay * 0.125;
    p.vy *= 1 - config.streamDecay * 0.125;
    p.age++;

    if (p.age > p.maxAge) {
      particles.splice(i, 1);
    }
  }
}

function updateCamera() {
  camera.x += (cameraTarget.x - camera.x) * config.theta;
  camera.y += (cameraTarget.y - camera.y) * config.theta;
  camera.zoom += (cameraTarget.zoom - camera.zoom) * config.theta;
}

function tickFrame() {
  updateNodes();
  updateParticles();
  updateCamera();

  if (tick % 3 === 0) {
    spawnParticle();
  }

  tick++;
}

setInterval(tickFrame, 16);
```

